// Runtime topology is generated by PCA deployment, not selected by a chat
// user or inherited from an operator shell. Keep that distinction in one
// small module so a local `pca run` cannot accidentally use Docker-only
// engine settings.

export const isContainerRuntime = (env = process.env) => env.BOT_AI_RUNTIME_CONTAINER === "1";

export const withoutContainerRuntime = (environment = process.env) => {
  const env = { ...environment };
  delete env.BOT_AI_RUNTIME_CONTAINER;
  return env;
};
